 13→  access_token: string;
 14→  refresh_token: string;
 15→  token_expires_at: number;
 16→  /** DPoP key material for sender-constrained tokens */
 17→  dpop_private_jwk?: JsonWebKey;
 18→  dpop_public_jwk?: JsonWebKey;
