 20→  /** DPoP-bound access token for MCP endpoints */
 21→  dpop_access_token?: string;
 22→  dpop_token_expires_at?: number;
 23→  /** Identity for intent submission */
 24→  identity_id?: string;
 25→  /** LLM proxy token for transparent Anthropic proxying */
 26→  proxy_token?: string;
 27→  proxy_token_expires_at?: string;
 28→};
 29→
 30→/** Per-repo auth entry in ~/.brain/config.json */
 31→export type RepoConfig = {
 32→  workspace: string;
 33→  client_id: string;
 34→  access_token: string;
 35→  refresh_token: string;
 36→  token_expires_at: number;
 37→  dpop_private_jwk?: JsonWebKey;
 38→  dpop_public_jwk?: JsonWebKey;
 39→  dpop_thumbprint?: string;
 40→  dpop_access_token?: string;
 41→  dpop_token_expires_at?: number;
 42→  identity_id?: string;
 43→  /** LLM proxy token for transparent Anthropic proxying */
 44→  proxy_token?: string;
 45→  proxy_token_expires_at?: string;
 46→};
 47→
 48→/** Root shape of ~/.brain/config.json */
 49→export type BrainGlobalConfig = {
 50→  server_url: string;
 51→  repos: Record<string, RepoConfig>;
 52→};
 53→
 54→// ---------------------------------------------------------------------------
 55→// Git root
 56→// ---------------------------------------------------------------------------
 57→
 58→/**
 59→ * Find the main repository root from any path, including worktrees.
 60→ *
 61→ * In a regular repo, `.git` is a directory → that dir is the root.
 62→ * In a worktree, `.git` is a file containing `gitdir: /path/to/main/.git/worktrees/<name>`.
 63→ * We follow the pointer back to the main repo so all worktrees share one config key.
 64→ */
 65→export function findGitRoot(from: string): string | undefined {
 66→  let dir = from;
 67→  while (dir !== "/") {
 68→    const gitPath = join(dir, ".git");
 69→    if (existsSync(gitPath)) {
 70→      if (statSync(gitPath).isFile()) {
 71→        return resolveWorktreeMainRoot(gitPath) ?? dir;
 72→      }
 73→      return dir;
 74→    }
 75→    dir = dirname(dir);
 76→  }
 77→  return undefined;
 78→}
 79→
 80→/** Read a worktree .git file and resolve to the main repo root. */
 81→function resolveWorktreeMainRoot(gitFile: string): string | undefined {
 82→  try {
 83→    const content = Bun.file(gitFile).textSync().trim();
 84→    const match = content.match(/^gitdir:\s*(.+)$/);
 85→    if (!match) return undefined;
 86→
 87→    const gitdir = resolve(dirname(gitFile), match[1]);
 88→    const dotGit = gitdir.replace(/\/worktrees\/[^/]+$/, "");
 89→    return dirname(dotGit);
 90→  } catch {
 91→    return undefined;
 92→  }
 93→}
 94→
 95→// ---------------------------------------------------------------------------
 96→// Global config (~/.brain/config.json)
 97→// ---------------------------------------------------------------------------
 98→
 99→function ensureBrainDir(): void {
100→  const dir = getBrainDir();
101→  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
102→}
103→
104→export async function loadGlobalConfig(): Promise<BrainGlobalConfig | undefined> {
105→  const file = Bun.file(getConfigPath());
106→  if (!(await file.exists())) return undefined;
107→  try {
108→    return await file.json() as BrainGlobalConfig;
109→  } catch {
110→    return undefined;
111→  }
112→}
113→
114→export async function saveGlobalConfig(config: BrainGlobalConfig): Promise<void> {
115→  ensureBrainDir();
116→  await Bun.write(getConfigPath(), JSON.stringify(config, null, 2) + "\n");
117→}
118→
119→/** Upsert a repo entry in the global config. Creates the file if needed. */
120→export async function saveRepoConfig(serverUrl: string, gitRoot: string, repo: RepoConfig): Promise<void> {
121→  const global = (await loadGlobalConfig()) ?? { server_url: serverUrl, repos: {} };
122→  global.server_url = serverUrl;
123→  global.repos[gitRoot] = repo;
124→  await saveGlobalConfig(global);
125→}
126→
127→// ---------------------------------------------------------------------------
128→// Resolved config (what consumers use)
129→// ---------------------------------------------------------------------------
130→
131→/** Resolve BrainConfig for the current repo from ~/.brain/config.json.
132→ *  The server URL can be overridden via the BRAIN_SERVER_URL env var. */
133→export async function loadConfig(): Promise<BrainConfig | undefined> {
134→  const gitRoot = findGitRoot(process.cwd());
135→  const global = await loadGlobalConfig();
136→  if (global && gitRoot && global.repos[gitRoot]) {
137→    const repo = global.repos[gitRoot];
138→    const serverUrl = process.env.BRAIN_SERVER_URL ?? global.server_url;
139→    return {
140→      server_url: serverUrl,
141→      workspace: repo.workspace,
142→      client_id: repo.client_id,
143→      access_token: repo.access_token,
144→      refresh_token: repo.refresh_token,
145→      token_expires_at: repo.token_expires_at,
146→      dpop_private_jwk: repo.dpop_private_jwk,
147→      dpop_public_jwk: repo.dpop_public_jwk,
148→      dpop_thumbprint: repo.dpop_thumbprint,
149→      dpop_access_token: repo.dpop_access_token,
150→      dpop_token_expires_at: repo.dpop_token_expires_at,
151→      identity_id: repo.identity_id,
152→      proxy_token: repo.proxy_token,
153→      proxy_token_expires_at: repo.proxy_token_expires_at,
154→    };
155→  }
156→  return undefined;
157→}
158→
159→export async function requireConfig(): Promise<BrainConfig> {
160→  const config = await loadConfig();
161→  if (!config) {
162→    console.error("Brain not configured. Run: brain init");
163→    process.exit(1);
164→  }
165→  return config;
166→}
