import { existsSync, mkdirSync, statSync } from "node:fs";
import { join, dirname, resolve } from "node:path";
import { homedir } from "node:os";

function getBrainDir() { return process.env.BRAIN_CONFIG_DIR ?? join(homedir(), ".brain"); }
function getConfigPath() { return join(getBrainDir(), "config.json"); }

/** Resolved config for a single repo — shape consumed by BrainHttpClient and all commands. */
export type BrainConfig = {
  server_url: string;
  workspace: string;
  client_id: string;
  access_token: string;
  refresh_token: string;
  token_expires_at: number;
  /** DPoP key material for sender-constrained tokens */
  dpop_private_jwk?: JsonWebKey;
  dpop_public_jwk?: JsonWebKey;
  dpop_thumbprint?: string;
  /** DPoP-bound access token for MCP endpoints */
  dpop_access_token?: string;
  dpop_token_expires_at?: number;
  /** Identity for intent submission */
  identity_id?: string;
  proxy_token_expires_at?: string;
};

/** Per-repo auth entry in ~/.brain/config.json */
export type RepoConfig = {
  workspace: string;
  client_id: string;
  access_token: string;
  refresh_token: string;
  token_expires_at: number;
  dpop_private_jwk?: JsonWebKey;
  dpop_public_jwk?: JsonWebKey;
  dpop_thumbprint?: string;
  dpop_access_token?: string;
  dpop_token_expires_at?: number;
  identity_id?: string;
  proxy_token_expires_at?: string;
};

/** Root shape of ~/.brain/config.json */
